INSERT INTO public.knowledge_documents VALUES (12, '草莓知識', '特性：草莓學名Fragaria ananassa Duchessne為F. virginiana和F.chiloensis雜交後代，由18世紀法國園藝學家A. N. Duchessne命名。Fragaria是由法語Fragrans(芳香之意)衍生而來，ananassa則是像鳳梨形狀的意思，形容其果實形狀。屬薔薇科( Rosaceae) 的多年生草本溫帶水果，廣受人們喜愛。世界各地都有分布，也是分布最廣的水果。
